#!/usr/bin/env bash
set -euo pipefail

# Freddy Fix It — tighten contractor signup + finish-signup nudge + insurance upload + unified doc file-types
# Ships: full-onboarding ContractorOnboarding (step-6 insurance-cert upload), AdminDashboard finish-signup
#        reminder, ContractorProfileCompletion (matched accept filter), finish-signup-nudge edge source, CLAUDE.md.
# Run: bash ~/Desktop/freddy-fixit/apply-tighten-signup.sh

cd "$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
echo "→ Syncing with GitHub…"
git fetch origin -q
git reset --hard origin/main -q

decode() {  # decode() <dest> <b64tmp> ; BSD+GNU safe (stdin redirect)
  mkdir -p "$(dirname "$1")"
  base64 --decode < "$2" > "$1"
  rm -f "$2"
}

